import React from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();

  const handleClick = () => {
    navigate(`/courses/${course.id}`);
  };

  const styles = {
    card: {
      background: 'white',
      borderRadius: '12px',
      padding: '1.5rem',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      textAlign: 'center',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid #e5e7eb',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'space-between',
      '&:hover': {
        transform: 'translateY(-5px)',
        boxShadow: '0 10px 25px rgba(0, 0, 0, 0.15)'
      }
    },
    cardIcon: {
      fontSize: '2.5rem',
      marginBottom: '1rem'
    },
    cardTitle: {
      fontSize: '1.25rem',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '0.5rem'
    },
    cardBranch: {
      color: '#6b7280',
      fontSize: '0.9rem',
      marginBottom: '1rem'
    },
    tagsContainer: {
      display: 'flex',
      justifyContent: 'center',
      gap: '0.5rem',
      marginBottom: '1.5rem',
      flexWrap: 'wrap'
    },
    tag: {
      background: '#e0e7ff',
      color: '#4f46e5',
      padding: '0.25rem 0.75rem',
      borderRadius: '12px',
      fontSize: '0.75rem',
      fontWeight: '500'
    },
    viewButton: {
      width: '100%',
      padding: '0.75rem',
      background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      fontWeight: '600',
      fontSize: '0.9rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'linear-gradient(90deg, #4338ca, #6d28d9)'
      }
    },
    stats: {
      display: 'flex',
      justifyContent: 'space-between',
      marginTop: '1rem',
      fontSize: '0.8rem',
      color: '#6b7280'
    }
  };

  return (
    <div style={styles.card} onClick={handleClick}>
      <div>
        <div style={styles.cardIcon}>📚</div>
        <h3 style={styles.cardTitle}>{course.name}</h3>
        <p style={styles.cardBranch}>
          {course.branch} • Sem {course.semester}
        </p>
        
        <div style={styles.tagsContainer}>
          <span style={styles.tag}>Notes</span>
          <span style={styles.tag}>PYQs</span>
          <span style={styles.tag}>Syllabus</span>
        </div>
      </div>
      
      <div>
        <div style={styles.stats}>
          <span>📄 {course.notes || 15}+</span>
          <span>📝 {course.pyqs || 30}+</span>
        </div>
        <button style={styles.viewButton}>
          View Materials →
        </button>
      </div>
    </div>
  );
};

export default CourseCard;
